import { createFileRoute, redirect, Outlet } from '@tanstack/react-router';
import { IsProfileComplete } from '@/utils/token';
import { Pathname } from '@/constants/Routes';

export const Route = createFileRoute('/_auth')({
  beforeLoad: ({ context, location }) => {
    if (!context.auth.isAuthenticated) {
      const fullPath = location.pathname + (location.hash || '');
      if (location.pathname === '/') {
        throw redirect({ to: '/login' });
      }
      throw redirect({
        to: '/login',
        search: { redirect: fullPath },
      });
    }

    const allowedForIncomplete = [Pathname.Profile_Edit, Pathname.Logout];

    if (!IsProfileComplete() && !allowedForIncomplete.some((p) => location.pathname.startsWith(p))) {
      throw redirect({ to: '/profile/edit' });
    }
  },
  component: () => <Outlet />,
});
